1566	      });
1567	    },
1568	    addViewFilter: (planViewId, filter) => {
1569	      const { elementsById } = get();
1570	      const pv = elementsById[planViewId];
1571	      if (!pv || pv.kind !== 'plan_view') return;
1572	      const prevFilters = (pv.viewFilters as import('./storeTypes').ViewFilter[] | undefined) ?? [];
1573	      const updated = [...prevFilters, filter];
1574	      set({ elementsById: { ...elementsById, [planViewId]: { ...pv, viewFilters: updated } } });
1575	    },
1576	    updateViewFilter: (planViewId, filterId, patch) => {
1577	      const { elementsById } = get();
1578	      const pv = elementsById[planViewId];
1579	      if (!pv || pv.kind !== 'plan_view') return;
1580	      const prevFilters = (pv.viewFilters as import('./storeTypes').ViewFilter[] | undefined) ?? [];
1581	      const updated = prevFilters.map((f) => (f.id === filterId ? { ...f, ...patch } : f));
1582	      set({ elementsById: { ...elementsById, [planViewId]: { ...pv, viewFilters: updated } } });
1583	    },
1584	    removeViewFilter: (planViewId, filterId) => {
1585	      const { elementsById } = get();
1586	      const pv = elementsById[planViewId];
1587	      if (!pv || pv.kind !== 'plan_view') return;
1588	      const prevFilters = (pv.viewFilters as import('./storeTypes').ViewFilter[] | undefined) ?? [];
1589	      const updated = prevFilters.filter((f) => f.id !== filterId);
1590	      set({ elementsById: { ...elementsById, [planViewId]: { ...pv, viewFilters: updated } } });
1591	    },
1592	  };
