750	function CustomTypeForm({
751	  discipline,
752	  onSave,
753	  onCancel,
754	}: {
755	  discipline: 'door' | 'window';
756	  onSave: (baseFamilyId: string, name: string, params: Record<string, unknown>) => void;
757	  onCancel: () => void;
758	}): JSX.Element {
759	  const families = BUILT_IN_FAMILIES.filter((f) => f.discipline === discipline);
760	  const [baseFamilyId, setBaseFamilyId] = useState(families[0]?.id ?? '');
761	  const [name, setName] = useState('');
762	  const [paramDraft, setParamDraft] = useState<Record<string, string>>({});
763	
764	  const baseFam = getFamilyById(baseFamilyId);
765	  const lengthParams = baseFam?.params.filter((p) => p.type === 'length_mm') ?? [];
766	
767	  function handleSave(): void {
768	    const params: Record<string, unknown> = { name: name.trim(), baseFamilyId };
769	    for (const p of lengthParams) {
770	      const raw = paramDraft[p.key];
771	      const val = raw !== undefined ? Number(raw) : (p.default as number);
772	      if (Number.isFinite(val)) params[p.key] = val;
773	    }
774	    onSave(baseFamilyId, name.trim(), params);
775	  }
776	
777	  return (
778	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
779	      <label className={LABEL_CLS}>
780	        Base family
781	        <select
782	          className={INPUT_CLS}
783	          value={baseFamilyId}
784	          onChange={(e) => {
785	            setBaseFamilyId(e.target.value);
786	            setParamDraft({});
787	          }}
788	        >
789	          {families.map((f) => (
790	            <option key={f.id} value={f.id}>
791	              {f.name}
792	            </option>
793	          ))}
794	        </select>
795	      </label>
796	      <label className={LABEL_CLS}>
797	        Type name
798	        <input
799	          className={INPUT_CLS}
800	          value={name}
801	          onChange={(e) => setName(e.target.value)}
802	          placeholder="e.g. Wide fire door"
803	          autoFocus
804	        />
805	      </label>
806	      {lengthParams.map((p) => (
807	        <label key={p.key} className={LABEL_CLS}>
808	          {p.label} (mm)
809	          <input
810	            className={INPUT_CLS}
811	            type="number"
812	            value={paramDraft[p.key] ?? String(p.default as number)}
813	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
814	          />
815	        </label>
816	      ))}
817	      <div className="flex gap-2 pt-0.5">
818	        <button
819	          type="button"
820	          disabled={!name.trim()}
821	          onClick={handleSave}
822	          className="flex-1 rounded border border-border bg-surface-strong px-2 py-0.5 text-[10px] hover:bg-accent-soft disabled:opacity-40"
823	        >
824	          Save type
825	        </button>
826	        <button
827	          type="button"
828	          onClick={onCancel}
829	          className="rounded border border-border px-2 py-0.5 text-[10px] hover:bg-surface-strong"
830	        >
831	          Cancel
832	        </button>
833	      </div>
834	    </div>
835	  );
836	}
